#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=500005;
struct node
{
	int x,y;
} a[N];
stack<int> st;
int n,q,nxt[N][25];
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>q;
	for(int i=1;i<=n;i++) 
	{
		cin>>a[i].x;
	}
	for(int i=1;i<=n;i++)
	{
		cin>>a[i].y;
	}
	for(int i=1;i<=n;i++)
	{
		while(!st.empty()&&(a[st.top()].x==a[i].x||a[st.top()].y<=a[i].y))
		{
			nxt[st.top()][0]=i;
			st.pop();
		}
		st.push(i);
	}
	for(int i=1;i<=log2(n);i++)
	{
		for(int j=1;j<=n;j++)
		{
			nxt[j][i]=nxt[nxt[j][i-1]][i-1];
			if(nxt[j][i]==0) nxt[j][i]=n+1;
		}
	}
	for(int i=1;i<=n;i++)
	{
		if(nxt[i][0]==0) nxt[i][0]=n+1;
	}
	while(q--)
	{
		int l,r,cnt=1;
		cin>>l>>r;
		for(int i=log2(n);i>=0;i--)
		{
			if(nxt[l][i]<=r)
			{
				cnt+=(1<<i);
				l=nxt[l][i];
			}
		}
		cout<<cnt<<"\n";
	}
	return 0;
}
